            part = f"died in {clean_obj}"
        elif pred == "nationality":
            part = f"is {clean_obj}"
        elif pred == "party":
            part = f"was a member of the {clean_obj} party"
        elif pred == "office":
            part = f"held the office of {clean_obj}"
        elif pred == "successor":
            part = f"was succeeded by {clean_obj}"
        elif pred == "predecessor":
            part = f"was preceded by {clean_obj}"
        elif pred == "spouse":
