        elif pred == "award":
            part = f"received the {clean_obj}"
        elif pred == "activeYearsStartDate":
            part = f"began service in {clean_obj}"
        elif pred == "activeYearsEndDate":
            part = f"served until {clean_obj}"
        elif pred == "hasDeputy":
            part = f"had {clean_obj} as deputy"
        elif pred == "inOfficeWhileVicePresident":
            part = f"served while {clean_obj} was vice president"
        elif pred == "inOfficeWhilePrimeMinister":
            part = f"served while {clean_obj} was prime minister"
        elif pred == "inOfficeWhilePresident":
            part = f"served while {clean_obj} was president"
        elif pred == "inOfficeWhileGovernor":
            part = f"served while {clean_obj} was governor"
        elif pred == "inOfficeWhileMonarch":
            part = f"served while {clean_obj} was monarch"
        elif pred == "serviceStartYear":
            part = f"started service in {clean_obj}"
        elif pred == "numberOfVotesAttained":
            part = f"received {clean_obj} votes"
        elif pred == "unit":
            part = f"was assigned to {clean_obj}"
        elif pred == "militaryBranch":
            part = f"was part of {clean_obj}"
        elif pred == "garrison":
            part = f"was stationed at {clean_obj}"
        elif pred == "trainerAircraft":
            part = f"used {clean_obj} as trainer aircraft"
        else:
            part = f"{pred} {clean_obj}"

        parts.append(part)

    # Join parts into one complex sentence with main subject at the beginning
    if not parts:
        return ""

    if len(parts) == 1:
        return f"{main_subject} {parts[0]}."
